import React from 'react';

interface UserCardProps {
  name: string;
  email: string;
  role: string;
  avatarUrl: string;
  onMessage: () => void;
}

const UserCard: React.FC<UserCardProps> = ({ name, email, role, avatarUrl, onMessage }) => {
  return (
    <div className="flex items-center p-4 bg-gray-800 text-white rounded-xl shadow-md">
      <img src={avatarUrl} alt="Avatar" className="w-16 h-16 rounded-full mr-4" />
      <div className="flex-1">
        <h3 className="text-lg font-semibold">{name}</h3>
        <p className="text-gray-400">{email}</p>
        <p className="text-gray-400 text-sm">Role: {role}</p>
      </div>
      <button
        onClick={onMessage}
        className="px-4 py-2 rounded-lg bg-blue-600 text-white hover:bg-blue-500 transition"
      >
        Message
      </button>
    </div>
  );
};

export default UserCard;

