import React from 'react';
import { Line } from 'react-chartjs-2';

interface StatisticsProps {
  totalSales: number;
  activeUsers: number;
  inventoryLevels: number;
  salesData: number[];
  userGrowthData: number[];
}

const Statistics: React.FC<StatisticsProps> = ({ totalSales, activeUsers, inventoryLevels, salesData, userGrowthData }) => {
  const salesChartData = {
    labels: ['Jan', 'Feb', 'Mar', 'Apr', 'May', 'Jun'],
    datasets: [
      {
        label: 'Sales',
        data: salesData,
        borderColor: 'rgba(75, 192, 192, 1)',
        backgroundColor: 'rgba(75, 192, 192, 0.2)',
        fill: true,
      },
    ],
  };

  const userGrowthChartData = {
    labels: ['Jan', 'Feb', 'Mar', 'Apr', 'May', 'Jun'],
    datasets: [
      {
        label: 'User Growth',
        data: userGrowthData,
        borderColor: 'rgba(153, 102, 255, 1)',
        backgroundColor: 'rgba(153, 102, 255, 0.2)',
        fill: true,
      },
    ],
  };

  return (
    <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
      <div className="p-6 bg-gray-800 text-white rounded-xl shadow-md">
        <h2 className="text-xl font-semibold mb-4">Dashboard Overview</h2>
        <div className="flex justify-between mb-4">
          <div>
            <p className="text-gray-400">Total Sales</p>
            <h3 className="text-2xl font-bold">${totalSales}</h3>
          </div>
          <div>
            <p className="text-gray-400">Active Users</p>
            <h3 className="text-2xl font-bold">{activeUsers}</h3>
          </div>
          <div>
            <p className="text-gray-400">Inventory Levels</p>
            <h3 className="text-2xl font-bold">{inventoryLevels}</h3>
          </div>
        </div>
        <Line data={salesChartData} options={{ maintainAspectRatio: false }} />
      </div>
      <div className="p-6 bg-gray-800 text-white rounded-xl shadow-md">
        <h2 className="text-xl font-semibold mb-4">User Growth</h2>
        <Line data={userGrowthChartData} options={{ maintainAspectRatio: false }} />
      </div>
    </div>
  );
};

export default Statistics;
